-- Donald Knuth (1–18)
(gen_random_uuid(), 'Un algoritmo debe verse para ser creído.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La optimización prematura es la raíz de todos los males.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El arte de programar es el arte de organizar la complejidad.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los mejores programas están escritos para que las máquinas los ejecuten rápido y los humanos los entiendan con claridad.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La ciencia es lo que entendemos lo suficiente como para explicárselo a una computadora. El arte es todo lo demás que hacemos.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Si encuentras que pasas casi todo tu tiempo en teoría, empieza a prestar atención a las cosas prácticas; mejorarás tus teorías.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los números aleatorios no deben generarse con un método elegido al azar.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Programar es la actividad de enseñarle a una computadora lo que quieres que haga de la forma más precisa posible.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La elegancia no es un lujo; en programación, la elegancia es la señal de que entendiste el problema correctamente.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un algoritmo ineficiente en una computadora rápida es derrotar el propósito de ambos.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El análisis de algoritmos es la gramática del razonamiento computacional.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Dominar las estructuras de datos es dominar la forma en que el pensamiento toma forma dentro de la máquina.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La recursión es la forma en que la naturaleza resuelve problemas: divídelos hasta que sean triviales.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Quien no mide la complejidad de su solución no controla realmente lo que ha construido.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El pensamiento computacional no es pensar como una máquina; es pensar con la precisión que las máquinas exigen.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Leer código ajeno es tan importante como escribir el propio; ambos forman al programador completo.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La abstracción es el instrumento más poderoso de la informática teórica y práctica.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un programa correcto que tarda en ejecutarse sigue siendo correcto; un programa rápido que falla no sirve de nada.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Robert C. Martin (19–36)
(gen_random_uuid(), 'El código limpio hace una cosa bien. El código sucio intenta hacer muchas cosas a la vez.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La verdadera medida de un buen programador es cuánto cuida el código que escribe.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Siempre deja el código un poco más limpio de lo que lo encontraste.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los nombres de las variables son la primera documentación de tu código; elige con cuidado.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Una función debe hacer una sola cosa, hacerla bien y no hacer nada más.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El código duplicado es la fuente más común de defectos en el software.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los comentarios que explican lo que hace el código son un olor; el código debe explicarse solo.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El refactoring no es arreglar bugs; es mejorar la estructura del código sin cambiar su comportamiento.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Las pruebas automatizadas son la red de seguridad que permite refactorizar con confianza.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El principio de responsabilidad única dice: una clase debe tener una única razón para cambiar.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El código abierto para extensión y cerrado para modificación es la madurez arquitectónica del software.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Depender de abstracciones en lugar de concreciones es el camino hacia el software flexible.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El código profesional no es solo código que funciona; es código que otros puedan leer, mantener y extender.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'TDD no es escribir pruebas primero; es diseñar pensando en la verificabilidad desde el inicio.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un buen arquitecto maximiza el número de decisiones que no se toman.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La deuda técnica, como la financiera, genera intereses; págala pronto o te ahogará.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El principio DRY no es solo evitar copiar y pegar; es que cada pieza de conocimiento tenga una sola representación.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Escribir código simple es más difícil que escribir código complicado; requiere más pensamiento.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Andrew Hunt & David Thomas (37–52)
(gen_random_uuid(), 'El programador pragmático piensa más allá del problema inmediato y siempre coloca el trabajo en su contexto más amplio.', 'Andrew Hunt', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'No te repitas: todo conocimiento debe tener una representación única, no ambigua y autoritativa en un sistema.', 'Andrew Hunt', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Arregla los problemas pequeños antes de que se conviertan en grandes; la ventana rota no reparada invita al caos.', 'Andrew Hunt', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Usa el poder de la línea de comandos; las interfaces gráficas son convenientes, pero no reemplazan la precisión del terminal.', 'David Thomas', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El mejor lenguaje de programación es el que mejor se adapta al problema que intentas resolver.', 'David Thomas', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Invierte regularmente en tu cartera de conocimiento; el mundo tecnológico no espera a los que se detienen.', 'Andrew Hunt', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Piensa en el código como comunicación; primero lo escribe el programador, luego lo lee la máquina, luego otros programadores.', 'David Thomas', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Las estimaciones son compromisos; si no puedes estimar con confianza, di que no sabes.', 'Andrew Hunt', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El debugging es el arte de eliminar lo que no puede estar mal hasta descubrir lo que debe estar mal.', 'David Thomas', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un diseño ortogonal garantiza que cambiar un componente no afecte a otros; esa independencia es libertad.', 'Andrew Hunt', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El prototipo descartable sirve para aprender; nunca entregues un prototipo como si fuera código de producción.', 'David Thomas', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Usa versiones de control desde el primer commit; no hay excusa para trabajar sin red de seguridad histórica.', 'Andrew Hunt', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Domina al menos un editor de texto profundamente; tu editor es la extensión de tus dedos en el código.', 'David Thomas', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los requisitos no se descubren; se inventan en colaboración entre el cliente y el desarrollador.', 'Andrew Hunt', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Haz que las cosas difíciles sean fáciles de hacer bien y difíciles de hacer mal; eso es diseño de API excelente.', 'David Thomas', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Aprende al menos un nuevo lenguaje de programación cada año; cada lenguaje te enseña a pensar de forma diferente.', 'Andrew Hunt', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Frederick Brooks (53–68)
(gen_random_uuid(), 'No hay bala de plata que elimine la complejidad esencial del software.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Añadir personas a un proyecto tardío lo retrasa aún más.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La complejidad del software es una propiedad esencial, no accidental; no puede diseñarse.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Planea desechar uno; de todos modos lo harás.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El programador, como el poeta, trabaja solo con la mente pura; construye castillos en el aire.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Las herramientas afiladas multiplican la eficiencia del artesano; un programador sin sus herramientas es mediocre.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El diseño del sistema debe reflejarse en la estructura del equipo que lo construye.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La segunda versión de un sistema siempre es la más peligrosa; el diseñador quiere corregir todo y termina comprometiendo la coherencia.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La integridad conceptual es la cualidad más importante de un diseño de sistema.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Una especificación que no pueda ser leída por el cliente no puede ser verificada por el programador.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El software bien diseñado es más fácil de cambiar; esa capacidad de cambio es su mayor valor a largo plazo.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La depuración es el momento de mayor aprendizaje en la vida de un programador; no la evites, domínala.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El buen juicio viene de la experiencia; la experiencia viene del mal juicio en proyectos anteriores.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Mostrar el progreso del software es más difícil que mostrar el de la construcción; el software no tiene masa visible.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El costo de mantener software mal escrito supera con creces el costo de escribirlo bien desde el principio.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los grandes sistemas de software son obras colectivas; la humildad técnica no es opcional, es arquitectónica.', 'Frederick Brooks', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Edsger Dijkstra (69–84)
(gen_random_uuid(), 'La prueba de que un programa es correcto sólo puede demostrar la presencia de errores, nunca su ausencia.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La simplicidad es condición previa de la fiabilidad.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Programar bien no es una habilidad técnica; es una forma disciplinada de pensar.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El uso del goto hace que el código sea ilegible y el flujo de control inmanejable.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Si la depuración es el arte de eliminar bugs, entonces programar debe ser el arte de no introducirlos.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La informática no trata sobre computadoras más de lo que la astronomía trata sobre telescopios.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un programa bien estructurado es aquel que puede ser entendido en partes sin necesidad de entender el todo.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La abstracción no es un lujo; es la única herramienta con la que podemos manejar la complejidad del mundo real.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Las computadoras son extraordinariamente rápidas haciendo cosas extremadamente estúpidas; el programador les da inteligencia.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Escribir código correcto es más difícil que parece; la única forma de hacerlo bien es pensar rigurosamente antes de escribir.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El problema con los lenguajes de programación no es el lenguaje; es que los programadores no piensan antes de programar.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Separar lo que cambia de lo que no cambia es la primera lección de diseño de software duradero.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El código que no puede ser probado formalmente no debería considerarse correcto por defecto.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La programación estructurada no es una restricción; es la liberación del caos del flujo arbitrario.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un invariante de bucle bien definido hace que la correctitud del algoritmo sea obvia, no una esperanza.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La elegancia no es cosmética; en algoritmos, la elegancia es eficiencia y claridad al mismo tiempo.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Tony Hoare (85–97)
(gen_random_uuid(), 'Hay dos maneras de construir software: hacerlo tan simple que obviamente no haya errores, o tan complejo que no haya errores obvios.', 'Tony Hoare', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La referencia nula fue mi error de mil millones de dólares; introducirla fue la decisión más fácil y más costosa de mi carrera.', 'Tony Hoare', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La corrección del software no es negociable; un sistema que falla aleatoriamente no es un sistema.', 'Tony Hoare', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La verificación formal es el único camino hacia la certeza en software crítico; la intuición no basta.', 'Tony Hoare', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un tipo de dato bien definido es un contrato entre el diseñador y el usuario de ese dato.', 'Tony Hoare', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La concurrencia bien diseñada no es complicada; la concurrencia mal diseñada es imposible de depurar.', 'Tony Hoare', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Primero haz que funcione, luego haz que sea correcto, luego haz que sea rápido; en ese orden y no en otro.', 'Tony Hoare', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La especificación algebraica de tipos de datos abstractos es más precisa que cualquier documentación en prosa.', 'Tony Hoare', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El debugging más efectivo es el que se hace antes de ejecutar: razonar sobre el código antes de correrlo.', 'Tony Hoare', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La modularidad es la forma más poderosa de gestionar la complejidad en sistemas grandes.', 'Tony Hoare', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El software seguro no accidentalmente es seguro; la seguridad debe ser diseñada desde el inicio.', 'Tony Hoare', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los invariantes de clase son la columna vertebral del diseño orientado a objetos correcto.', 'Tony Hoare', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Confiar en la lógica del programa sin probarlo formalmente es como confiar en un puente sin calcularlo.', 'Tony Hoare', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Alan Kay (98–110)
(gen_random_uuid(), 'El mejor camino para predecir el futuro es inventarlo.', 'Alan Kay', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La perspectiva vale ochenta puntos de cociente intelectual.', 'Alan Kay', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La orientación a objetos trata los objetos como entidades que se comunican mediante mensajes, no como colecciones de datos.', 'Alan Kay', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El software bien diseñado envejece como el buen vino; el mal software se agría como la leche.', 'Alan Kay', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La mayoría del software de hoy es como la pirámide del antiguo Egipto: miles de trabajadores empujando bloques pero sin arquitectura real.', 'Alan Kay', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El cambio de paradigma no es incremental; es una ruptura con la forma de pensar anterior.', 'Alan Kay', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Smalltalk demostró que un lenguaje puede ser tan simple que cabe en una tarjeta y tan poderoso que construye sistemas completos.', 'Alan Kay', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Las interfaces de usuario deben ser tan intuitivas que hasta un niño las use; si no, el problema es el diseño, no el usuario.', 'Alan Kay', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La computadora personal fue concebida como un instrumento musical para la mente humana, no como una calculadora glorificada.', 'Alan Kay', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Pensar en objetos que se envían mensajes es más natural que pensar en procedimientos que manipulan datos.', 'Alan Kay', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La abstracción nos permite ignorar los detalles sin perder el control; esa es su magia.', 'Alan Kay', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un lenguaje de programación que no cambia tu forma de pensar no vale la pena aprenderlo.', 'Alan Kay', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Las ideas realmente buenas en computación se pueden expresar en muy pocas palabras; si necesitas muchas, probablemente no estás en lo correcto.', 'Alan Kay', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Kent Beck (111–124)
(gen_random_uuid(), 'Haz que funcione, luego hazlo correcto, luego hazlo rápido.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El desarrollo guiado por pruebas es un método de diseño más que de testing.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Escribe la prueba más simple posible que podría fallar, luego escribe el código más simple que la haga pasar.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El refactoring continuo mantiene el sistema saludable; sin él, el código se deteriora inevitablemente.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La programación en parejas no reduce la velocidad; duplica la revisión y reduce los errores costosos.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Integra con frecuencia; cada hora sin integración es una hora de deuda de integración acumulándose.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los smells de código son señales de que algo está mal en el diseño, no en la funcionalidad.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El código más flexible no es el más genérico; es el más simple que puede ser extendido cuando sea necesario.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La comunicación entre desarrolladores es tan importante como la comunicación entre módulos del sistema.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un test que tarda mucho en ejecutarse no se ejecuta; los tests deben ser rápidos para ser útiles.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La confianza en el código sin tests es una ilusión; el sistema puede estar funcionando hoy y roto mañana.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un diseño simple tiene todos los tests pasando y no tiene duplicación ni oscuridad innecesaria.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La valía de una suite de tests se mide por su capacidad de capturar regresiones, no por su cobertura numérica.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'XP no es un conjunto de prácticas; es una forma de trabajar basada en el respeto, la comunicación y la retroalimentación continua.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Martin Fowler (125–138)
(gen_random_uuid(), 'El refactoring es el proceso de cambiar el código de tal manera que no altere el comportamiento externo pero mejore la estructura interna.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Cualquier tonto puede escribir código que una computadora entienda; los buenos programadores escriben código que los humanos entiendan.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Si tu código necesita un comentario para entenderse, primero intenta reescribirlo para que sea autoexplicativo.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los patrones de diseño no son recetas; son vocabulario compartido para describir soluciones a problemas recurrentes.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La arquitectura es el conjunto de decisiones de diseño que desearías haber tomado correctamente desde el principio.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La entrega continua es la capacidad de llevar cambios de software a producción de forma segura y rápida en cualquier momento.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un microservicio bien definido puede ser reemplazado completamente sin afectar al resto del sistema.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La indirección es la herramienta del diseñador; permite cambiar implementaciones sin romper contratos.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Una buena suite de tests permite que cualquier miembro del equipo refactorice sin miedo.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El código es comunicación; cada función y variable es una declaración de intención.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La separación entre lógica de dominio e infraestructura es la diferencia entre software adaptable y software frágil.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un modelo de dominio bien diseñado habla el idioma del negocio y lo traduce al idioma del código sin pérdida de significado.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los patrones empresariales de arquitectura son la gramática del software a escala.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Sin disciplina de integración continua, el trabajo en paralelo genera conflictos que crecen exponencialmente con el tiempo.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Linus Torvalds (139–151)
(gen_random_uuid(), 'El código que habla por sí mismo es el mejor código que existe.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El software libre no es gratis porque no cuesta dinero; es libre porque respeta tu libertad.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Hablar es barato. Muéstrame el código.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El buen gusto en programación es saber cuándo un enfoque simple es mejor que uno ingenioso.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los sistemas operativos bien diseñados se componen de capas de abstracción cada una resolviendo un nivel de complejidad diferente.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El código que funciona en mi máquina no es suficiente; debe funcionar en todas las máquinas del mundo.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El control de versiones no es opcional; es tan fundamental como guardar el trabajo.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La colaboración distribuida a escala global es posible cuando el modelo de trabajo está bien diseñado desde el inicio.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los bugs que no puedes reproducir son los más peligrosos; la reproducibilidad es el primer paso del debugging.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La optimización a nivel del kernel requiere entender el hardware; sin ese conocimiento, la optimización es ciega.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Mantener compatibilidad hacia atrás no es cobardía; es respeto por los usuarios que dependen de tu software.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El diseño de sistemas distribuidos require pensar en los fallos como el caso normal, no como la excepción.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un commit pequeño y enfocado cuenta una historia clara; un commit grande y mezclado no cuenta nada.', 'Linus Torvalds', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Brian Kernighan (152–163)
(gen_random_uuid(), 'Controla la complejidad del software dividiéndola: cada parte debe ser comprensible de forma aislada.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La depuración es dos veces más difícil que escribir el código; si escribes el código más inteligente que puedes, no podrás depurarlo.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
