(gen_random_uuid(), 'Un programa bien estructurado es más fácil de probar, mantener y extender que uno escrito sin diseño previo.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
