(gen_random_uuid(), 'Las herramientas de línea de comandos componen; los programas pequeños que hacen una cosa bien son más valiosos que los monolitos.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El texto plano es el formato más duradero; mientras exista computación, el texto plano será legible.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Escribe código que sea difícil de usar incorrectamente; eso vale más que cualquier documentación.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Probar con casos extremos revela más bugs que probar con casos normales; busca los límites de tu lógica.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La filosofía Unix de hacer una cosa bien ha demostrado ser más duradera que cualquier arquitectura monolítica.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El código portable es código bien escrito; las suposiciones sobre el entorno son deuda oculta.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un buen tutorial enseña a pensar, no solo a ejecutar; los mejores tutoriales te hacen entender el por qué.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Harold Abelson (164–175)
(gen_random_uuid(), 'Los programas deben ser escritos para que la gente los lea y solo incidentalmente para que las máquinas los ejecuten.', 'Harold Abelson', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La complejidad no es una propiedad del problema; es una propiedad del nivel de abstracción que elegimos.', 'Harold Abelson', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La recursión es la forma más natural de describir problemas que tienen estructura autosimilar.', 'Harold Abelson', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El lenguaje de programación es un medio de expresión del pensamiento computacional, no solo una herramienta de instrucción.', 'Harold Abelson', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Las funciones de orden superior expresan patrones de computación que no pueden nombrarse de otra manera.', 'Harold Abelson', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El intérprete metacircular demuestra que un lenguaje puede describirse completamente en sí mismo; esa es su mayor profundidad.', 'Harold Abelson', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La programación funcional hace explícitas las dependencias entre datos; eso la hace más fácil de razonar.', 'Harold Abelson', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Entender la diferencia entre procedimiento e iteración es entender la naturaleza del cálculo computacional.', 'Harold Abelson', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La abstracción de datos separa el uso de una estructura de datos de su implementación; esa separación es poder.', 'Harold Abelson', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El pensamiento computacional no es exclusivo de los informáticos; es una forma general de resolver problemas con precisión.', 'Harold Abelson', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La evaluación diferida permite trabajar con estructuras de datos infinitas; es la abstracción del tiempo de computación.', 'Harold Abelson', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Separar la descripción de un proceso de la implementación del proceso es el corazón del diseño de software.', 'Harold Abelson', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Peter Norvig (176–187)
(gen_random_uuid(), 'La IA no trata sobre simular la inteligencia humana; trata sobre resolver problemas que requieren inteligencia para resolverlos.', 'Peter Norvig', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Programar no se aprende leyendo; se aprende escribiendo código, cometiendo errores y corrigiéndolos.', 'Peter Norvig', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
