(gen_random_uuid(), 'La heurística es una estimación informada; sin ella, la búsqueda ciega en espacios grandes es inviable.', 'Peter Norvig', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Dominar la programación requiere diez años de práctica deliberada; no hay atajos para la maestría.', 'Peter Norvig', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
