(gen_random_uuid(), 'La representación del conocimiento es la mitad del problema en inteligencia artificial; la otra mitad es el razonamiento sobre esa representación.', 'Peter Norvig', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Entender los fundamentos matemáticos de los algoritmos permite adaptarlos a nuevos dominios; sin esa base, solo puedes copiarlos.', 'Peter Norvig', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
