(gen_random_uuid(), 'Python es el idioma franco de la computación moderna; su claridad reduce la distancia entre la idea y su implementación.', 'Peter Norvig', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Aprender a leer código de otros es tan importante como aprender a escribirlo; la comprensión de código es una habilidad separada.', 'Peter Norvig', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Steve McConnell (188–200)
(gen_random_uuid(), 'La construcción de software es el proceso más complejo y cognitivamente exigente que la humanidad ha emprendido sistemáticamente.', 'Steve McConnell', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El código es leído diez veces más de lo que se escribe; optimiza para la lectura, no para la escritura.', 'Steve McConnell', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los buenos desarrolladores producen diez veces más que los mediocres no por escribir más rápido sino por tomar mejores decisiones.', 'Steve McConnell', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La revisión de código es la práctica de calidad con mejor relación costo-beneficio en el desarrollo de software.', 'Steve McConnell', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un buen nombre de variable reduce el número de comentarios necesarios en al menos un cincuenta por ciento.', 'Steve McConnell', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La gestión del alcance es la habilidad de ingeniería más valiosa y menos enseñada en las universidades.', 'Steve McConnell', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Probar antes de codificar obliga a pensar en el comportamiento esperado; eso mejora el diseño más que cualquier patrón.', 'Steve McConnell', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El código defensivo anticipa los usos incorrectos; cada suposición no verificada es una bomba de tiempo latente.', 'Steve McConnell', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La pseudocodificación antes de implementar reduce los errores de lógica y clarifica el pensamiento sobre el algoritmo.', 'Steve McConnell', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El costo de corregir un defecto crece exponencialmente cuanto más tarde se encuentra en el ciclo de desarrollo.', 'Steve McConnell', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La complejidad ciclomática mide el número de caminos de ejecución; valores altos predicen la probabilidad de defectos.', 'Steve McConnell', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un buen programador es aquel que mira en ambas direcciones antes de cruzar una calle de sentido único.', 'Steve McConnell', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Documentar las decisiones de diseño y sus razones es más valioso que documentar el código en sí.', 'Steve McConnell', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Rich Hickey (201–211)
(gen_random_uuid(), 'La simplicidad no es lo mismo que la facilidad; lo simple no está entrelazado, lo fácil es solo familiar.', 'Rich Hickey', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El estado mutable es la fuente de la mayoría de los bugs concurrentes; la inmutabilidad los elimina por diseño.', 'Rich Hickey', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Entrelazar conceptos en el código crea complejidad accidental que no existe en el problema original.', 'Rich Hickey', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los valores inmutables son más fáciles de razonar, compartir y cachear; el estado mutable tiene un costo cognitivo enorme.', 'Rich Hickey', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El polimorfismo basado en tipos viola la separación de datos y comportamiento que hace al código realmente flexible.', 'Rich Hickey', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Las abstracciones leaky no mienten; simplemente revelan que la abstracción es insuficiente para el problema.', 'Rich Hickey', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La composición de funciones puras es la forma más segura de construir sistemas grandes y predecibles.', 'Rich Hickey', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El problema con la orientación a objetos es que mezcla identidad, estado y comportamiento cuando a menudo solo necesitas uno de los tres.', 'Rich Hickey', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Clojure no es un lenguaje de programación; es una forma de pensar sobre la información y su transformación.', 'Rich Hickey', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El tiempo es una dimensión frecuentemente ignorada en el diseño de software; los datos cambian y el sistema debe saberlo.', 'Rich Hickey', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Un buen diseño comienza por hacer preguntas difíciles sobre qué necesita cambiar y qué debe permanecer estable.', 'Rich Hickey', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Paul Graham (212–223)
(gen_random_uuid(), 'Los hackers son artistas; el buen código es arte funcional que deleita tanto al que lo usa como al que lo lee.', 'Paul Graham', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La brevedad es la almendía del alma; en código, la concisión reduce los lugares donde pueden esconderse los bugs.', 'Paul Graham', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Lisp no es solo un lenguaje; es una notación para describir algoritmos que resulta ser ejecutable.', 'Paul Graham', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El software exitoso se construye en capas; cada capa es un lenguaje de dominio específico para la capa superior.', 'Paul Graham', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Hacer las cosas simples que importan primero es la única forma de llegar a la complejidad que vale la pena.', 'Paul Graham', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El prototipado rápido revela las suposiciones incorrectas antes de que se conviertan en arquitectura permanente.', 'Paul Graham', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La elegancia del código es una señal de que el programador entendió el problema lo suficientemente bien como para resolverlo limpiamente.', 'Paul Graham', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los mejores programadores no son los que conocen más lenguajes; son los que conocen cuándo usar cada herramienta.', 'Paul Graham', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La recursión no asusta a quien entiende que un problema complejo es simplemente un problema pequeño más sus variaciones.', 'Paul Graham', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Resolver problemas difíciles hace mejores programadores; los problemas triviales producen programadores triviales.', 'Paul Graham', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El software no envejece como el hardware; envejece como el conocimiento, que se vuelve obsoleto cuando el mundo cambia.', 'Paul Graham', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Pensar en el usuario final mientras escribes código es la diferencia entre software que se usa y software que se tolera.', 'Paul Graham', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Eric Raymond (224–232)
(gen_random_uuid(), 'Dados suficientes ojos, todos los bugs son superficiales.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El bazar es más eficiente que la catedral para encontrar y corregir errores en software complejo.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Cada programa que usas tiene código escrito por alguien que también aprendió; ningún código nace perfecto.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La cultura hacker valora la elegancia, la ingeniosidad y la solución mínima que resuelve el problema máximo.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El principio KISS dice que los sistemas simples son más robustos que los complejos en condiciones del mundo real.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Publicar pronto, publicar frecuentemente; cada versión es retroalimentación y cada retroalimentación mejora el software.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los programadores brillantes que resuelven solos hacen sistemas que nadie más puede mantener; la colaboración produce sistemas que todos pueden mejorar.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La filosofía Unix es acumular pequeñas herramientas que hacen una cosa bien y componer soluciones con ellas.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El código abierto no es una metodología; es una epistemología: el conocimiento mejora cuando es examinado por muchos.', 'Eric Raymond', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- Jon Bentley (233–241)
(gen_random_uuid(), 'Antes de optimizar, mide; sin datos reales, la optimización es solo superstición con código.', 'Jon Bentley', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los problemas de programación más elegantes son aquellos donde la solución correcta es también la más simple.', 'Jon Bentley', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El algoritmo correcto es frecuentemente mil veces más rápido que la optimización de un algoritmo incorrecto.', 'Jon Bentley', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La estructura de datos correcta puede reducir un algoritmo de complejidad cuadrática a lineal; elige primero la estructura.', 'Jon Bentley', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Programar perlas son soluciones elegantes a problemas difíciles; encontrarlas requiere pensamiento profundo, no código rápido.', 'Jon Bentley', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Escribir el programa más simple que resuelve el problema es más difícil que escribir el más complicado.', 'Jon Bentley', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Entender el problema antes de escribir una sola línea de código multiplica la calidad del resultado final.', 'Jon Bentley', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La búsqueda binaria es la demostración más pura de que dividir el problema a la mitad resuelve exponencialmente más rápido.', 'Jon Bentley', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El software de calidad no es aquel que no tiene bugs; es aquel donde los bugs no pueden sobrevivir mucho tiempo.', 'Jon Bentley', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),

-- John Carmack (242–250)
(gen_random_uuid(), 'El rendimiento es una característica; si no mides, no puedes mejorar lo que no ves.', 'John Carmack', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La programación de bajo nivel revela verdades que la abstracción oculta; conocer el hardware es conocer los límites reales.', 'John Carmack', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Iterar rápidamente sobre ideas es la única forma de descubrir cuáles son realmente buenas y cuáles solo parecen buenas.', 'John Carmack', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El código legible no es solo un estándar de cortesía; es una estrategia de mantenimiento a largo plazo.', 'John Carmack', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La optimización de sistemas de tiempo real requiere entender no solo el algoritmo sino el modelo de memoria del hardware.', 'John Carmack', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Los mejores programas de videojuegos son arte de ingeniería: cada ciclo de CPU contado, cada byte de memoria justificado.', 'John Carmack', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'La determinación de resolver un problema difícil, combinada con el rigor de no aceptar soluciones a medias, produce código excelente.', 'John Carmack', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'El profiler es el instrumento del programador que busca la verdad sobre el rendimiento; sin él, todo es especulación.', 'John Carmack', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding'),
(gen_random_uuid(), 'Construir sistemas en tiempo real enseña que cada decisión de diseño tiene un costo medible; esa disciplina mejora todo el código que escribes después.', 'John Carmack', 'philosophy', 'es', 'down', 'free', false, 'coding', 'fundamentals', ARRAY['discipline','learning'], true, 'coding')

ON CONFLICT (text, author) DO NOTHING;

COMMIT;
